-- Enrichment marathon batch: Piwigo, Pixelfed, Pixpa, Places Scout, Planable, Plane, Plane Project Management, PlanetScale

-- ── Piwigo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Piwigo is a free, open-source, self-hosted photo gallery and image management platform for organizing, tagging and publishing photo collections on the web, with an optional paid cloud-hosting service at Piwigo.com.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted plans from EUR29/month$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small core team, historically around 10 members)$q$, company_size),
  headquarters = COALESCE($q$Saint-Sebastien-sur-Loire, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Dutch$q$, $q$Polish$q$, $q$Danish$q$, $q$Turkish$q$, $q$Russian$q$, $q$Chinese (Simplified)$q$]::text[],
  seo_title = COALESCE($q$Piwigo Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Piwigo review: open-source, self-hosted photo gallery software with albums, plugins and cloud hosting. See features, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Piwigo is a free, open-source photo management and gallery platform originally released in 2002 by French developer Pierrick Le Gall (as an evolution of his earlier PhpWebGallery project started in 2001). It is distributed under the GNU GPL and can be self-hosted on any PHP and MySQL/MariaDB web server, or run as a managed cloud service through Piwigo.com, a separate hosting business operated by the same team (PigoLabs SAS, based near Nantes, France) that funds ongoing development of the open-source core. Piwigo lets individuals and organizations organize photos into nested albums and categories, apply granular per-album and per-group permissions, batch-manage large libraries, and extend functionality through more than 200 community plugins and customizable themes. It supports uploads from desktop tools like digiKam, Shotwell and Lightroom, plus official mobile apps, and its interface has been translated into a wide range of languages by its community. Piwigo differentiates itself from consumer photo apps like Google Photos or Flickr by targeting users who want full data ownership and self-hosting control, and from other open-source galleries (such as Coppermine or Zenphoto) through its long development history, active plugin ecosystem and dedicated commercial hosting option. The self-hosted software is entirely free; Piwigo.com's managed hosting is billed annually across four tiers ranging from a Pro plan at EUR29/month (10 GB storage, one administrator) up to a VIP plan at EUR399/month (1000 GB storage, unlimited administrators and phone support), with additional storage add-ons available on every tier. Piwigo is used by museums, universities, tourism boards, research institutions, photography studios and community organizations that need a durable, extensible photo archive rather than a disposable social feed. After more than two decades of continuous development, over 130 releases and roughly 2.8 million downloads, Piwigo remains a niche but stable choice for teams that value openness and control. Its main alternatives include SmugMug, Zenfolio, Pixieset and Flickr for hosted options, and Coppermine or Zenphoto among other self-hosted, open-source galleries.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dc6e0788-b827-42b0-bfab-4a75e09f4a12';

