-- ── Pixelfed ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pixelfed is a free, open-source, federated photo-sharing platform built on ActivityPub, offering an ad-free, chronological, Instagram-like experience across independently run Fediverse servers.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted or join a public instance); third-party managed hosting from about $19/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small independent open-source project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (founder based in Canada)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pixelfed Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pixelfed review: the open-source, federated Instagram alternative on ActivityPub. Explore features, hosting costs and top Fediverse alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pixelfed is a free, open-source, federated photo and video-sharing platform released in December 2018 by Canadian developer Daniel Supernault. It is licensed under AGPLv3+ and built on ActivityPub, the same open protocol used by Mastodon, PeerTube and Friendica, which lets Pixelfed accounts interoperate with those platforms as part of the broader Fediverse. Rather than being one centrally owned service, Pixelfed is a piece of software that anyone can self-host, and users typically join a public instance such as pixelfed.social, or a smaller community-run server whose administrator sets its own moderation policy. The platform is explicitly positioned as an ethical, privacy-respecting alternative to Instagram: it shows no advertising, does not sell user data, avoids third-party analytics, and defaults to reverse-chronological feeds instead of an engagement-ranking algorithm. Features include posts of up to ten photos or videos, Stories, curated collections, hashtags, geo-tagging, two-factor authentication, and post-level audience controls (public, followers-only or unlisted). Official native iOS and Android apps launched in January 2025, expanding access beyond the web client. Because Pixelfed has no venture-capital backing or advertising revenue, it is funded through donations, Patreon sponsorships from users, and grants such as NGI Zero; individual instance operators, including the flagship pixelfed.social, cover their own hosting costs and have periodically reported funding shortfalls relative to expenses. Supernault also created Loops, a federated, TikTok-like short-video platform built on similar principles, extending the same decentralized, non-commercial model to video. Pixelfed targets privacy-conscious individuals, niche and regional communities, and open-web advocates who want an Instagram-style experience without corporate ownership, algorithmic feeds or advertising, as well as organizations that want to self-host their own photo-sharing community. Its closest comparison point is Instagram itself, though Pixelfed is better understood as competing with other Fediverse and independent photo platforms; relevant alternatives and adjacent products include Mastodon (for the broader federated social experience), PeerTube, Flickr and newer independent photography-social apps such as Glass.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '18949653-684b-4d6b-9f7f-0ba4d9594f29';

