-- ── Planable ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Planable is a collaboration-first social media content planning, approval and publishing platform that lets teams and agencies plan, review and schedule posts across major social networks.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$33/workspace/month (billed monthly)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (acquired by SE Ranking in August 2025)$q$, company_size),
  headquarters = COALESCE($q$Chisinau, Moldova$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Planable Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Planable review: collaborative social media planning and approval platform. Compare features, pricing plans and top scheduling alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Planable is a social media management platform built around team and client collaboration, letting marketing teams and agencies plan, review, approve and publish content across multiple social networks from one workspace. The company was founded in 2016 by Xenia Muntean, Nicolae Gudumac and Vlad Calus in Chisinau, Moldova, and raised a small seed round of roughly $120,000 from investors including Angular Ventures, Fribourg Capital and GapMinder VC. In August 2025, Planable was acquired by SE Ranking, an SEO software platform used by over a million marketers, and now operates as a standalone product within SE Ranking's broader ecosystem. Planable's core differentiator is its collaboration and approval layer: rather than functioning primarily as a scheduler, it offers a visual content calendar and native feed-style previews so teams can see exactly how a post will look on each platform, real-time comments and inline suggestions for editing copy or creative, and customizable approval workflows that can be optional, required or run through multiple sign-off levels before publishing. It supports scheduling and publishing to Facebook, Instagram, TikTok, LinkedIn, X (Twitter), YouTube, Pinterest and Google Business Profile, and organizes work into multi-brand workspaces with labels and campaigns for agencies handling several clients. Add-on modules extend the platform with analytics and reporting, and a unified social inbox for managing comments and direct messages with sentiment-based prioritization and AI-assisted replies. Pricing is subscription-based and billed per workspace: the Basic plan starts at $33/workspace/month for 60 posts and 4 social pages, Pro costs $49/workspace/month for 150 posts and 10 social pages plus API access, and Enterprise is custom-priced with unlimited posts, SSO and dedicated support; Analytics and Social Inbox are separately priced add-ons available on any plan. There is no permanent free tier, only a 50-post free trial. Planable targets marketing agencies managing client accounts, multi-brand and multi-location companies, and in-house marketing teams that need structured content review before anything goes live. Its main competitors in the broader social media management category include Buffer, Hootsuite, Later and Sprout Social, though Planable is most often chosen specifically for its stronger collaboration and client-approval workflow rather than pure scheduling breadth.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd33a449d-fed5-4373-8185-a70d16979e8b';

