-- ── Plane ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Plane (plane.com) is a Y Combinator-backed global payroll, HR and compliance platform for hiring, paying and managing US employees, international contractors and Employer-of-Record workers from one API-first, agent-ready system. It is a distinct company from the open-source project management tool also called Plane, hosted at plane.so.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$0/month for HRIS; $19-$499 per person/month depending on worker type$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Plane (plane.com) Review 2026: Payroll and HR Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Plane review: Y Combinator-backed global payroll, HR and EOR platform for contractors and employees. See pricing, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Plane, at plane.com, is a global payroll, HR and compliance platform for hiring, paying and managing US employees, international contractors and Employer-of-Record (EOR) workers from a single system. The company was founded in 2017 by Staszek Kolarzowski and Matt Pelc and went through Y Combinator's Winter 2017 (W17) batch; it is headquartered in San Francisco, California. Plane's core product unifies an HRIS, US payroll, global contractor payments (in 240+ countries and 70+ local currencies) and EOR hiring (in 100+ countries) into one platform, with automated compliance features such as multi-state payroll tax registration, W-8/W-9 collection, 1099 filing and locally compliant contract generation. Its more recent positioning leans into agentic automation: Plane exposes an open API, CLI and MCP (Model Context Protocol) support so that AI agents, including tools like Claude, can perform payroll and HR actions directly, and it offers a Slack-based Plane Agent for real-time payroll and HR queries. Pricing is usage-based and transparent: the HRIS layer is free for all worker types, US W-2 employees cost $19/month, international contractors cost $39/month, and EOR hires cost $499/month, with no setup fees or long-term contracts. Plane targets fast-growing startups and remote-first companies that need to hire globally without setting up local legal entities, as well as engineering and product teams that want programmatic, agent-callable access to payroll and HR data. Important disambiguation: plane.com is operated by a different company from Plane Project Management, the popular open-source Jira and Linear alternative available at plane.so, founded in 2022 in Hyderabad and San Francisco and backed by OSS Capital. The two products share only a name and coincidentally similar branding; they have separate founders, separate funding histories and serve entirely different markets, payroll and HR versus project management. Plane's payroll-category competitors include Deel, Remote, Rippling and Papaya Global, all of which offer overlapping EOR, contractor payment and global payroll capabilities.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '41688164-bff2-4d0a-8c55-4d847c936f12';

