UPDATE tools SET
  short_description = COALESCE($q$Plane (at plane.so) is an open-source, AI-native project management platform and Jira/Linear alternative for tracking work items, sprints, docs and workflows, available as a managed cloud service or self-hosted. It is a separate company from the payroll and HR platform also called Plane, at plane.com.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 12 seats; paid plans from $6/seat/month$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Hyderabad, India and Delaware/San Francisco, United States (dual headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Plane Review 2026: Open-Source PM Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Plane (plane.so) review: open-source Jira and Linear alternative with work items, cycles, docs and AI. Compare pricing, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Plane, at plane.so and maintained under the GitHub organization makeplane, is an open-source, AI-native project management platform positioned as an alternative to Jira, Linear, Asana, Monday.com and ClickUp. It was founded in late 2022 by brothers Vamsi Kurama (CEO) and Vihar Kurama (COO), operating with a dual headquarters structure spanning Hyderabad, India and a Delaware/San Francisco US entity. The project launched publicly via its makeplane/plane GitHub repository, quickly gained developer traction as a lightweight, self-hostable alternative to Jira's complexity, and has grown to tens of thousands of GitHub stars, making it one of the most starred open-source project management tools available. In April 2024, Plane raised a $4 million seed round led by OSS Capital, the dedicated open-source-focused fund founded by Joseph Jacks; this remains its primary disclosed institutional funding. The product is released under the AGPL-3.0 license and is built with TypeScript/React on the frontend and Python/Django on the backend, and can be deployed as a fully managed Plane Cloud service or self-hosted via Docker or Kubernetes, including air-gapped enterprise deployments. Core capabilities include work items (issues) with rich-text editing, Cycles for sprint tracking with burndown charts, Modules for breaking large projects into components, customizable views and filters, a built-in Wiki for documentation linked to work items, and Plane AI for AI-assisted workflows and automation. Pricing follows a freemium, per-seat model: a Free tier supports up to 12 users with core project management features and 500 AI credits per seat; Pro costs $6/seat/month with unlimited seats and expanded AI credits, wiki, time tracking and integrations; Business costs $13/seat/month adding templates, intake forms, customer profiles and advanced dashboards; and Enterprise Grid is custom-priced for private and managed deployments, SSO/LDAP, audit logs and migration services. Plane targets engineering, product and startup teams that want an open-source, self-hostable Jira/Linear alternative with modern UX. Its main competitors are Jira, Linear, ClickUp, Asana and Monday.com. Note: despite sharing the name Plane, this project management product is an entirely separate company from the payroll and HR platform found at plane.com, which was founded independently in 2017 in San Francisco and has no ownership relationship with plane.so.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '68399520-7bce-4cbd-8fad-93972635411f';

