-- ── PlanetScale ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PlanetScale is a cloud database platform offering managed, horizontally scalable MySQL (via Vitess) and PostgreSQL databases with Git-style branching, built by the original creators of Vitess.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$From $5/month (Postgres non-HA); Vitess plans from $39/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$51-200 employees (approximately 80-95 as of 2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PlanetScale Review 2026: Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PlanetScale review: managed Vitess-based MySQL and Postgres database platform with branching. Compare pricing, features and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PlanetScale is a cloud database platform that provides fully managed, horizontally scalable MySQL databases built on Vitess, alongside a newer managed PostgreSQL product. It was founded in 2018 by Jiten Vaidya and Sugu Sougoumarane, the original co-creators and maintainers of the open-source Vitess project, which they built at YouTube starting around 2010 to scale MySQL to petabyte scale across tens of thousands of nodes. The company is headquartered in San Francisco, California, and has raised over $100 million across multiple rounds, including a $3 million seed in 2018 led by SignalFire, a $22 million Series A led by Andreessen Horowitz, a $30 million Series B led by Insight Partners, and a $50 million Series C led by Kleiner Perkins. PlanetScale's core technical differentiator is Vitess-powered horizontal sharding combined with Git-style, non-blocking schema branching and online schema changes, which let developers create isolated database branches, test schema changes safely, and merge them without downtime; the platform also offers Query Insights, connection pooling, and SOC 2 Type 2, HIPAA and PCI DSS Level 1 compliance. In March 2024, PlanetScale discontinued its free Hobby tier and reduced staff as part of a strategic shift away from the self-serve hobbyist and indie-developer segment toward enterprise customers, and it has since expanded into managed PostgreSQL, including a bare-metal PlanetScale Metal NVMe offering, alongside its original Vitess/MySQL product. Pricing today starts around $5/month for a single-node Postgres development database and $39/month for entry-level Vitess clusters, scaling to tens of thousands of dollars per month for large, high-availability, multi-region deployments. The Vitess technology underlying PlanetScale is used directly by large-scale platforms such as Slack, GitHub, Block and Bloomberg. PlanetScale targets engineering teams at startups and enterprises that need MySQL- or Postgres-compatible databases at scale with modern developer workflows like branching and preview environments. Its main competitors include AWS Aurora, Google Cloud SQL/AlloyDB, Neon, CockroachDB and Supabase.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '424ed87f-e0ac-4a99-869c-2cecd795e4b1';

