INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Album and category hierarchy$q$, $q$Organize photos into nested albums, categories and tags for large libraries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Batch photo management$q$, $q$Upload, edit metadata and manage permissions for many photos at once.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Plugin and theme ecosystem$q$, $q$Extend functionality with 200+ community plugins and customizable themes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Granular permissions$q$, $q$Control who can view, upload to or administer specific albums and groups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Desktop and mobile uploaders$q$, $q$Upload directly from digiKam, Shotwell, Lightroom or the official Piwigo mobile apps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Piwigo.com managed hosting$q$, $q$Optional paid cloud hosting removes the need to self-host and maintain servers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Multi-language interface$q$, $q$The software and community translations support a wide range of languages.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Free and open source with full source code access and no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Highly extensible through plugins and themes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Granular album and group permission controls suited to teams and organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Mature project with over two decades of continuous development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Optional managed hosting removes server maintenance burden$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Self-hosted setup requires PHP/MySQL server knowledge and ongoing maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Interface feels dated compared to newer, design-forward gallery tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Piwigo.com hosting is billed annually only, with no monthly option currently$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Smaller ecosystem and community than mainstream competitors like SmugMug or Flickr$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Is Piwigo free?$q$, $q$Yes, the core Piwigo software is free and open source under the GNU GPL; you can self-host it on your own server at no cost. Piwigo.com offers optional paid managed hosting starting at EUR29/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$What is the difference between Piwigo.org and Piwigo.com?$q$, $q$Piwigo.org distributes the free, self-hosted open-source software; Piwigo.com is a separate paid cloud-hosting service run by the same team for people who do not want to manage their own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$What server requirements does self-hosted Piwigo have?$q$, $q$Piwigo requires a PHP-compatible web host with a MySQL or MariaDB database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Does Piwigo support video and audio files?$q$, $q$Yes, video and audio are supported on Piwigo.com plans, and all file formats are supported from the Team tier upward.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Can I migrate away from Piwigo if I stop using it?$q$, $q$Yes, because Piwigo is open source and self-hostable, you retain full access to your database and files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Does Piwigo have mobile apps?$q$, $q$Yes, official apps and third-party uploaders including pLoader, digiKam, Shotwell and Lightroom plugins can upload photos to a Piwigo gallery.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Who maintains Piwigo?$q$, $q$Piwigo was created by French developer Pierrick Le Gall and is maintained by a small core team plus community contributors, funded partly by the Piwigo.com hosting business.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$What are Piwigo's main alternatives?$q$, $q$Common alternatives include Coppermine, Zenphoto, SmugMug, Flickr and Pixieset, depending on whether self-hosting or a hosted service is preferred.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Self-hosted photo archive for organizations$q$, $q$Museums, universities and research institutions use Piwigo to catalog and share large historical or scientific photo collections under their own control.$q$, $q$IT teams and archivists at institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Client and team photo sharing$q$, $q$Photography studios and marketing teams use albums and permission groups to share proofs and assets with clients or colleagues.$q$, $q$Photographers and small creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Community and event photo galleries$q$, $q$Clubs, schools and tourism boards use Piwigo to let members or contributors upload and browse shared event photos.$q$, $q$Community organizers and hobbyist administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Self-Hosted (Community)$q$, $q$Free$q$, $q$One-time (software)$q$, NULL, $q$["Full open-source software","Unlimited photos, limited only by your own server","200+ plugins and themes","Community support via forum"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Pro$q$, $q$EUR29/month$q$, $q$Billed annually$q$, NULL, $q$["1 administrator, unlimited users","10 GB storage","Image, video and audio files","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Team$q$, $q$EUR99/month$q$, $q$Billed annually$q$, NULL, $q$["3 administrators, unlimited contributors","100 GB storage","All file formats supported","Priority email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$Enterprise$q$, $q$EUR199/month$q$, $q$Billed annually$q$, NULL, $q$["5 administrators, unlimited contributors","250 GB storage","All file formats supported","Priority email support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$VIP$q$, $q$EUR399/month$q$, $q$Billed annually$q$, NULL, $q$["Unlimited administrators, unlimited contributors","1000 GB storage","All file formats supported","Priority email and phone support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Piwigo is open-source photo management software that lets individuals and organizations organize, tag and publish photo collections on the web. First released in 2002 by French developer Pierrick Le Gall, it grew out of an earlier project called PhpWebGallery and was renamed Piwigo in 2009.$q$, $q$The software can be downloaded and self-hosted for free on any PHP-compatible server, or run through Piwigo.com, a separate paid cloud-hosting service operated by the same team for people who prefer not to manage their own infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Piwigo organizes photos into nested albums and categories with granular, group-based permissions, making it suited to teams that need to control exactly who can view, upload to or administer specific collections.$q$, $q$Its functionality can be extended through more than 200 community-built plugins and themes, and photos can be uploaded from desktop tools such as digiKam, Shotwell and Lightroom, or from Piwigo's own mobile apps.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Piwigo software is free and open source under the GNU GPL, with no cost for self-hosting on your own server.$q$, $q$Piwigo.com's managed cloud hosting is billed annually across four tiers, from Pro at EUR29/month up to VIP at EUR399/month, with additional storage available as an add-on on every plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('dc6e0788-b827-42b0-bfab-4a75e09f4a12', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Federated ActivityPub network$q$, $q$Pixelfed accounts can interact with Mastodon, Friendica, PeerTube and other Fediverse platforms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Chronological, algorithm-free feed$q$, $q$Posts appear in reverse-chronological order rather than being ranked by an engagement algorithm.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$No ads or third-party trackers$q$, $q$The platform does not sell user data or show advertising.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Stories and collections$q$, $q$Supports ephemeral stories and curated photo or video collections similar to mainstream apps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Self-hostable instances$q$, $q$Anyone can run their own Pixelfed server and moderate their own community.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Native iOS and Android apps$q$, $q$Official mobile apps launched in January 2025 alongside the web app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Privacy controls$q$, $q$Post-level audience settings, two-factor authentication and no invasive analytics.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Free, open source and AGPL-licensed with no corporate ownership$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$No ads, algorithmic manipulation or data resale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Interoperates with the broader Fediverse, including Mastodon and PeerTube$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Users can choose or self-host an instance aligned with their values$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Chronological feed favored by users wanting less algorithmic noise$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Smaller user base and network effects than Instagram$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Instance funding relies heavily on donations, creating sustainability risk for some servers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Feature parity with Instagram, such as advanced discovery and shopping, is still developing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Choosing and trusting the right instance administrator adds friction for new users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Self-hosting requires server administration skills$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Is Pixelfed free?$q$, $q$Yes, Pixelfed is free, open-source software; joining a public instance like pixelfed.social is free, and instance operators fund servers through donations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Who created Pixelfed?$q$, $q$Canadian developer Daniel Supernault created Pixelfed and released it in December 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$What is the Fediverse?$q$, $q$The Fediverse is a network of independently operated, interoperable social platforms, including Pixelfed, Mastodon, PeerTube and Friendica, that communicate using the open ActivityPub protocol.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Can I self-host Pixelfed?$q$, $q$Yes, Pixelfed is AGPLv3+ licensed and can be self-hosted on your own server, or you can join an existing public or community instance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Does Pixelfed have mobile apps?$q$, $q$Yes, official iOS and Android apps launched in January 2025.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$How is Pixelfed funded?$q$, $q$Through donations, Patreon sponsorships and grants such as NGI Zero, rather than venture capital or advertising.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$What is Loops and how does it relate to Pixelfed?$q$, $q$Loops is a federated, TikTok-like short video platform also created by Daniel Supernault, built on similar Fediverse principles.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$How is Pixelfed different from Instagram?$q$, $q$Pixelfed is open source, decentralized, ad-free and chronological, while Instagram is a centralized, ad-supported, algorithmically ranked platform owned by Meta.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Privacy-conscious photo sharing$q$, $q$Individuals who want an Instagram-like experience without ads, tracking or algorithmic feeds join or self-host a Pixelfed instance.$q$, $q$Privacy-focused individual users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Community and niche instances$q$, $q$Communities such as photographers, artists or regional groups run dedicated Pixelfed instances with their own moderation policies.$q$, $q$Community moderators and niche communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Federated brand or creator presence$q$, $q$Creators and organizations that want to participate in the open Fediverse alongside Mastodon use Pixelfed for visual content.$q$, $q$Independent creators and open-web advocates$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Self-Hosted or Public Instance$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source AGPLv3 software","Join any public instance for free","ActivityPub federation with the Fediverse","No ads or tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$Managed Hosting (third-party providers)$q$, $q$From about $19/month$q$, $q$Monthly$q$, NULL, $q$["Managed server setup for a small instance","Maintenance and updates handled by the provider","Suited to running a private or small community instance"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pixelfed is free, open-source software for federated photo and video sharing, created by Canadian developer Daniel Supernault and first released in December 2018 under the AGPLv3+ license.$q$, $q$Instead of one central company running the service, Pixelfed is a protocol-based network: anyone can self-host an instance, and users typically sign up on a public server such as pixelfed.social or a smaller community-run instance.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pixelfed uses ActivityPub, the same open protocol behind Mastodon, PeerTube and Friendica, so Pixelfed accounts can follow and interact with people on those platforms as part of the Fediverse.$q$, $q$It offers Instagram-style features such as multi-photo posts, Stories and collections, but defaults to a chronological feed with no engagement-ranking algorithm, no ads and no third-party trackers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pixelfed itself is free: the software is open source, and joining a public instance costs nothing, with servers typically funded by donations from their communities.$q$, $q$For those who want a dedicated or private instance without self-managing a server, third-party managed hosting providers offer Pixelfed instances starting at roughly $19/month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('18949653-684b-4d6b-9f7f-0ba4d9594f29', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Portfolio website builder$q$, $q$200+ responsive, designer-made templates with a drag-and-drop visual editor and no coding required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Client proofing galleries$q$, $q$Password-protected galleries with commenting, favoriting and multi-user proofing for client review.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Zero-commission online store$q$, $q$Sell prints, digital downloads, products and services without Pixpa taking a cut of sales.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Integrated blogging and SEO tools$q$, $q$Built-in blog with on-page SEO controls to drive organic traffic to a portfolio.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Automated print fulfillment$q$, $q$Integration with the WHCC lab for automated print order fulfillment.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$24/7 live human support$q$, $q$Round-the-clock live chat support staffed by humans rather than bots.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Purpose-built for photographers and visual creatives, not a generic website builder$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Combines portfolio, store, galleries and blog in one subscription instead of stitching together multiple tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$No commission fees on store sales$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Strong customer support reputation, rated 4.7/5 on Capterra across 600+ reviews$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Generous 15-day free trial with no credit card required, plus a 30-day money-back guarantee$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Design flexibility is more limited than fully custom-code website builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Fewer third-party integrations and apps than larger platforms like Squarespace$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Advanced e-commerce features are less robust than dedicated platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$The dedicated client-gallery-only plan requires a separate subscription from the main site plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$What is Pixpa used for?$q$, $q$Pixpa is used to build portfolio websites, client proofing galleries, blogs and online stores, primarily for photographers, artists and other visual creatives.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Does Pixpa charge commission on store sales?$q$, $q$No, Pixpa does not take a commission on sales made through its built-in e-commerce store.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Is there a free trial?$q$, $q$Yes, Pixpa offers a 15-day free trial with no credit card required, plus a 30-day money-back guarantee.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Can I use Pixpa just for client galleries?$q$, $q$Yes, Pixpa offers a standalone Client Gallery plan starting at $5/month for photographers who only need proofing galleries.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Do students get a discount?$q$, $q$Yes, students and educators can receive discounts of up to 55 percent.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Where is Pixpa based?$q$, $q$Pixpa is headquartered in New Delhi, India, with a US corporate entity registered in Delaware.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$What are Pixpa's main alternatives?$q$, $q$Common alternatives include Squarespace, Format, SmugMug, Zenfolio and Pixieset.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Does Pixpa include a free domain?$q$, $q$Yes, annual subscribers receive a free custom domain for the first year.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Photographer portfolio and client delivery$q$, $q$Wedding, portrait and commercial photographers use Pixpa to showcase work, deliver proofs and sell prints in one workflow.$q$, $q$Professional and freelance photographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Artist and designer online presence$q$, $q$Illustrators, fine artists and designers use Pixpa's templates to build a professional portfolio without coding.$q$, $q$Visual artists, illustrators and designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Small creative business e-commerce$q$, $q$Creatives sell prints, digital downloads or services directly from their portfolio site using Pixpa's built-in store.$q$, $q$Independent creative businesses and freelancers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Basic$q$, $q$$5.40/month$q$, $q$Billed annually$q$, NULL, $q$["Portfolio website with visual editor","Client galleries","Blogging tools","Free domain for first year"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Creator$q$, $q$$9/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Basic","Expanded storage and product limits","Additional client gallery features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Professional$q$, $q$$12/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Creator","Higher usage limits","Advanced store features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Advanced$q$, $q$$15/month$q$, $q$Billed annually$q$, NULL, $q$["Everything in Professional","Highest usage limits","Priority feature access"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$Client Gallery (standalone)$q$, $q$$5/month$q$, $q$Billed annually$q$, NULL, $q$["Proofing galleries only","Commenting and favoriting","Image delivery to clients"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pixpa is an all-in-one website builder built specifically for photographers, artists and creative professionals, combining a portfolio site, client proofing galleries, an online store and a blog in one subscription.$q$, $q$Founded in 2011 and headquartered in New Delhi, India, Pixpa has grown as a bootstrapped company focused on serving visual creatives who need both a professional presentation and the ability to sell their work online.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers over 200 responsive, designer-made templates with a visual, drag-and-drop editor that requires no coding, alongside client galleries built for proofing, commenting and image delivery.$q$, $q$Its built-in store lets creatives sell prints, digital downloads, products and services without Pixpa taking a commission, and an integrated blog with SEO tools supports organic discovery for a creative's portfolio.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eef4f17c-1c20-4cb2-9bf7-47a0e5632c8c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pixpa offers four annual subscription tiers, from Basic at $5.40/month up to Advanced at $15/month, plus a standalone Client Gallery plan starting at $5/month for photographers who only need proofing.$q$, $q$All plans include a 15-day free trial with no credit card required and a 30-day money-back guarantee, and annual subscribers receive a free custom domain for the first year.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Search Performance rank tracking$q$, $q$Tracks local and organic search rankings against named competitors across major search engines.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Geo-Matrix visualization$q$, $q$Displays ranking visibility on a map grid to show how results change block by block or city by city.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$GBP Radar$q$, $q$Monitors Google Business Profile listings for changes and issues.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Reputation monitoring$q$, $q$Aggregates and tracks reviews across 20 or more review sites in one dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Citation Intel$q$, $q$Discovers where a business is mentioned or cited online.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Listing Audit$q$, $q$Checks NAP (name, address, phone) consistency across directories and listings.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Deep, granular Geo-Matrix visualization not offered by every local SEO competitor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Covers rank tracking, reviews, citations and listing audits in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Custom, modular pricing lets agencies pay only for the tools they use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Personal, high-touch customer support frequently praised by users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Pricing is not published and requires contacting sales for a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Interface has been described by some reviewers as dated$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Less brand recognition than larger local SEO platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Custom packages can make cost comparison against competitors harder$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$What does Places Scout do?$q$, $q$It is local SEO software that tracks search rankings, monitors Google Business Profiles, aggregates reviews, and audits citations and listing consistency for businesses with one or many locations.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Who is Places Scout for?$q$, $q$Primarily marketing agencies managing multiple client locations and enterprise brands with many physical locations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$How much does Places Scout cost?$q$, $q$Pricing is custom and based on the number of locations and keywords tracked; you must request a quote or demo from the company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$What is Geo-Matrix?$q$, $q$A feature that visualizes local search rankings on a map grid, showing how visibility changes from block to block or across a city.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Does Places Scout track review sites?$q$, $q$Yes, it monitors reviews across 20 or more major review platforms alongside Google.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$What are alternatives to Places Scout?$q$, $q$Common alternatives include BrightLocal, Whitespark, Moz Local and Local Falcon.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Does Places Scout check business listing accuracy?$q$, $q$Yes, its Listing Audit feature verifies NAP (name, address, phone) consistency across directories.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Is there a free trial?$q$, $q$Places Scout offers a free demo upon request rather than a self-serve free trial.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Multi-location rank tracking for agencies$q$, $q$Agencies managing several client locations use Places Scout to track rankings and competitors across each market from one dashboard.$q$, $q$Local SEO and digital marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Enterprise multi-location reputation management$q$, $q$Brands with many physical locations monitor reviews and Google Business Profile health across all sites.$q$, $q$Enterprise and franchise marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Local visibility auditing$q$, $q$Marketers use Geo-Matrix and Listing Audit to diagnose why a business ranks inconsistently across a service area.$q$, $q$Local SEO consultants and analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$Custom Package$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Pay only for the modules you use","Search Performance rank tracking","Geo-Matrix visualization","GBP Radar","Reputation Monitoring","Citation Intel","Listing Audit"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Places Scout is a local SEO software platform focused on giving agencies and multi-location brands visibility into how their businesses rank, are reviewed, and are cited across the web.$q$, $q$In operation since 2011, the platform is built around automated data collection, drawing on more than 400 data points per business to power its rank tracking, reputation and citation tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Its Search Performance and Geo-Matrix tools track local and organic rankings and visualize them on a map grid, showing how visibility changes across a service area down to the block level.$q$, $q$GBP Radar, Reputation Monitoring, Citation Intel and Listing Audit round out the platform, covering Google Business Profile health, multi-site review tracking, citation discovery and NAP consistency checks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48120309-810d-426d-85b1-0cc890be92d9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Places Scout does not publish fixed pricing tiers; instead, it sells custom packages sized to the number of locations and keywords a customer needs to track.$q$, $q$Prospective customers request a demo or quote directly from the company rather than signing up through a self-serve pricing page.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Visual content calendar and feed preview$q$, $q$Plan posts in a calendar or native feed-style preview across platforms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Real-time collaboration$q$, $q$Comment, suggest edits and annotate posts directly with teammates or clients.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Customizable approval workflows$q$, $q$Set optional or required, single- or multi-level approval steps before publishing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Multi-platform scheduling$q$, $q$Publish and schedule to Facebook, Instagram, TikTok, LinkedIn, X, YouTube, Pinterest and Google Business Profile.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Unified social inbox (add-on)$q$, $q$Manage comments and DMs across platforms with sentiment-based prioritization and AI-assisted replies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Analytics and reporting (add-on)$q$, $q$Track performance metrics, audience insights and best-time-to-post recommendations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Multi-brand workspaces$q$, $q$Organize campaigns, labels and content separately across multiple brands or clients.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Strong focus on team and client collaboration and approval, not just scheduling$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Unlimited users included on all plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Native feed preview shows how posts will actually look per platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Public API and integrations available on higher tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$No permanent free plan, only a post-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Analytics and Social Inbox are priced as separate add-ons rather than bundled$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Per-workspace pricing can get expensive for agencies managing many clients$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Enterprise-grade features like SSO and dedicated support require custom pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$What is Planable used for?$q$, $q$Planable is used to plan, collaborate on, approve and schedule social media content across multiple platforms and brands.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Does Planable have a free plan?$q$, $q$No, Planable offers a free trial of 50 posts with no time limit rather than a permanent free tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$How much does Planable cost?$q$, $q$Plans start at $33/workspace/month for Basic, with Pro at $49/workspace/month and custom Enterprise pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Who owns Planable now?$q$, $q$Planable was acquired by SE Ranking, an SEO software platform, in August 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$What platforms does Planable support?$q$, $q$Facebook, Instagram, TikTok, LinkedIn, X (Twitter), YouTube, Pinterest and Google Business Profile.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Does Planable include analytics?$q$, $q$Analytics is available as a paid add-on for $12/workspace/month on any plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$What makes Planable different from Buffer or Hootsuite?$q$, $q$Planable emphasizes real-time collaboration and structured approval workflows for teams and clients, rather than focusing primarily on scheduling.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Who founded Planable?$q$, $q$Planable was founded in 2016 by Xenia Muntean, Nicolae Gudumac and Vlad Calus in Chisinau, Moldova.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Agency client approval workflows$q$, $q$Agencies use Planable's approval steps so clients can review and approve posts before they go live.$q$, $q$Social media and marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Multi-brand content coordination$q$, $q$Companies managing several brands or locations organize content per workspace with labels and campaigns.$q$, $q$Multi-brand and multi-location marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$In-house team collaboration$q$, $q$Marketing teams use comments and suggestions to refine posts together before scheduling.$q$, $q$In-house marketing and content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Basic$q$, $q$$33/workspace/month$q$, $q$Monthly or yearly (2 months free annually)$q$, NULL, $q$["60 posts per month","4 social pages","Unlimited users","Feed and calendar views","AI post rewrite and generation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Pro$q$, $q$$49/workspace/month$q$, $q$Monthly or yearly (2 months free annually)$q$, NULL, $q$["150 posts per month","10 social pages","Public API access","30-day version history","Bulk approvals"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Unlimited posts","50 social pages","SSO integration","Dedicated account manager","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planable is a social media management platform focused on team and client collaboration, letting marketers plan, review, approve and publish content across multiple networks from a shared workspace.$q$, $q$Founded in 2016 in Chisinau, Moldova, by Xenia Muntean, Nicolae Gudumac and Vlad Calus, Planable was acquired by SEO platform SE Ranking in August 2025 and now runs as a standalone product within that company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's calendar and native feed previews show exactly how a post will appear on each network, while comments, suggestions and customizable approval workflows let teams and clients review content before it goes live.$q$, $q$Planable supports scheduling across Facebook, Instagram, TikTok, LinkedIn, X, YouTube, Pinterest and Google Business Profile, with multi-brand workspaces, labels and campaigns for agencies managing several clients.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing is billed per workspace: Basic starts at $33/month for 60 posts and 4 social pages, Pro is $49/month for 150 posts and 10 social pages, and Enterprise is custom-priced with unlimited posts and SSO.$q$, $q$Analytics and Social Inbox are available as separate paid add-ons on any plan, and there is no permanent free tier, only a 50-post free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Unified HRIS$q$, $q$Single directory and reporting layer for employees, contractors and EOR workers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Global contractor payments$q$, $q$Pay contractors in 240+ countries using 70+ local currencies with W-8/W-9 and 1099 handling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$US W-2 payroll$q$, $q$Multi-state payroll with automated tax filing, Form I-9/W-4 support and flexible pay schedules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Employer of Record (EOR)$q$, $q$Hire full-time employees in 100+ countries without setting up a local legal entity.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Agent-ready API, CLI and MCP support$q$, $q$Lets AI agents and internal tools perform payroll and HR actions programmatically.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Slack-based Plane Agent$q$, $q$An AI assistant for real-time payroll and HR questions inside Slack.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Automated compliance$q$, $q$Handles state tax registration and locally compliant contract generation automatically.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Transparent, pay-per-person pricing with no setup fees or minimums$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Combines HRIS, US payroll, global contractors and EOR in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Early mover in exposing payroll and HR actions to AI agents via MCP and CLI$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Backed by Y Combinator with an established operating history since 2017$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$EOR pricing at $499/person/month is a significant recurring cost for smaller teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Company details such as funding and team size are not fully disclosed publicly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$The newer agentic positioning means some AI-driven features are still maturing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Shares its name with an unrelated, well-known open-source project management tool, which can cause buyer confusion$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Is Plane (plane.com) the same as the Plane project management tool?$q$, $q$No, they are unrelated companies that happen to share the name Plane. Plane.com is a payroll and HR platform founded in 2017 (YC W17); the open-source project management tool called Plane is hosted at plane.so and was founded separately in 2022.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$What does Plane (plane.com) do?$q$, $q$It is a global payroll, HR and compliance platform for hiring and paying US employees, international contractors and Employer-of-Record workers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$How much does Plane cost?$q$, $q$HRIS is free; US employees cost $19/month, international contractors cost $39/month, and EOR hires cost $499/month, all billed per person.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Does Plane support AI agents?$q$, $q$Yes, Plane offers an open API, CLI and MCP support so AI agents can perform payroll and HR tasks, plus a Slack-based Plane Agent assistant.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$In how many countries can Plane pay contractors?$q$, $q$Plane supports contractor payments in 240+ countries and EOR hiring in 100+ countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Who founded Plane?$q$, $q$Plane was founded in 2017 by Staszek Kolarzowski and Matt Pelc, and went through Y Combinator's W17 batch.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$What are alternatives to Plane?$q$, $q$Common alternatives include Deel, Remote, Rippling and Papaya Global.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Is there a free trial?$q$, $q$Plane's HRIS tier is free for all worker types; paid tiers are billed per person per month based on usage rather than a traditional trial.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Hiring international contractors$q$, $q$Startups pay contractors across 240+ countries in local currencies while automating 1099 and W-8 tax paperwork.$q$, $q$Startups and remote-first companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Employer of Record hiring$q$, $q$Companies hire full-time employees abroad without setting up a local legal entity using Plane's EOR service.$q$, $q$Companies expanding into new countries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$AI-agent-driven payroll operations$q$, $q$Engineering and operations teams automate payroll and HR workflows programmatically via Plane's API, CLI and MCP support.$q$, $q$Technical operations and finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$HRIS$q$, $q$$0/month per person$q$, $q$Monthly$q$, NULL, $q$["Guided hiring and onboarding","Contractor and employee directory","Custom reports","Time and holiday tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Contractors$q$, $q$$39/month per person$q$, $q$Monthly$q$, NULL, $q$["Payments in 240+ countries","70+ local currencies","W-8/W-9 collection and 1099 filing","Optional health insurance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$Employees (US)$q$, $q$$19/month per person$q$, $q$Monthly$q$, NULL, $q$["Multi-state W-2 payroll","Automated tax filing","Form I-9/W-4 support","Flexible pay schedules"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$EOR$q$, $q$$499/month per person$q$, $q$Monthly$q$, NULL, $q$["Hire in 100+ countries without a local entity","Locally compliant contracts","Immigration and visa assistance","Health insurance and benefits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plane, at plane.com, is a global payroll and HR platform that lets companies hire, pay and manage US employees, international contractors and Employer-of-Record workers from one system. It was founded in 2017 by Staszek Kolarzowski and Matt Pelc, went through Y Combinator's W17 batch, and is based in San Francisco.$q$, $q$Note for buyers: this is a different company from the well-known open-source project management tool also named Plane, which is hosted at plane.so, founded separately in 2022 and unrelated to this payroll business beyond sharing a name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plane combines an HRIS, US W-2 payroll, global contractor payments in 240+ countries, and Employer-of-Record hiring in 100+ countries into one platform, with automated compliance such as tax registration, 1099 filing and locally compliant contracts.$q$, $q$It leans into agentic automation with an open API, CLI and MCP support that let AI agents perform payroll and HR actions directly, plus a Slack-based Plane Agent assistant for real-time queries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41688164-bff2-4d0a-8c55-4d847c936f12', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plane prices per person per month based on worker type: the HRIS is free, US employees cost $19/month, international contractors cost $39/month, and EOR hires cost $499/month.$q$, $q$There are no setup fees, minimum charges or long-term contracts, and customers can cancel at any time.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Work items and issue tracking$q$, $q$Rich-text work items with sprints, epics, sub-issues and triage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Cycles$q$, $q$Sprint-style cycles with burndown charts and velocity tracking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Modules$q$, $q$Break large projects into manageable components or feature areas.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Multiple views$q$, $q$Board, list, spreadsheet, Gantt/timeline and calendar views with custom filters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Built-in Wiki$q$, $q$Documentation and pages linked directly to project work items.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Plane AI$q$, $q$AI-assisted work item creation, summaries and workflow automation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Self-hosted or cloud deployment$q$, $q$Deploy via Docker/Kubernetes for full data control, or use the managed Plane Cloud service.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Open source (AGPL-3.0) with a free self-hosted option and full source access$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Generous free cloud tier for up to 12 seats$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Modern, fast interface compared to legacy tools like Jira$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Self-hosting and air-gapped deployment support enterprise and compliance needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Backed by OSS Capital, a fund focused on sustainable open-source businesses$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Younger product, founded in 2022, with a smaller feature set than mature tools like Jira in some enterprise areas$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$AI credits are metered per seat, which can add complexity to cost planning$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Self-hosting requires infrastructure management$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Smaller third-party integration and app marketplace than Atlassian's Jira ecosystem$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Is Plane (plane.so) free?$q$, $q$Yes, Plane offers a free cloud tier for up to 12 seats, plus a fully free self-hosted option since the software is open source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Who owns Plane?$q$, $q$Plane is developed by a company founded by Vamsi Kurama and Vihar Kurama in 2022, backed by OSS Capital.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Is Plane the same company as the payroll platform Plane at plane.com?$q$, $q$No, they are unrelated companies that happen to share the name Plane; plane.so is the project management tool, and plane.com is a separate payroll and HR company founded in 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Can Plane be self-hosted?$q$, $q$Yes, Plane is released under the AGPL-3.0 license and can be self-hosted via Docker or Kubernetes, including air-gapped deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$What are Plane's main competitors?$q$, $q$Jira, Linear, ClickUp, Asana and Monday.com.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Does Plane have AI features?$q$, $q$Yes, Plane AI provides AI-assisted work item creation and workflow automation, with AI credits included per seat.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$How much does Plane cost?$q$, $q$Free for up to 12 seats; Pro is $6/seat/month, Business is $13/seat/month, and Enterprise Grid is custom-priced.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Has Plane raised funding?$q$, $q$Yes, Plane raised a $4 million seed round led by OSS Capital in April 2024.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Open-source Jira replacement for engineering teams$q$, $q$Engineering teams migrate from Jira to Plane for a faster, self-hostable issue tracker with cycles and modules.$q$, $q$Software engineering and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Self-hosted project management for regulated environments$q$, $q$Organizations with strict data-control requirements self-host Plane, including air-gapped deployments.$q$, $q$Enterprises and regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Startup product and roadmap planning$q$, $q$Startups use initiatives, cycles and the built-in wiki to plan roadmaps and track sprints in one tool.$q$, $q$Startup product and engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Free$q$, $q$$0/seat/month$q$, $q$Monthly$q$, NULL, $q$["Up to 12 seats","500 AI credits per seat","Work items, cycles and modules","Custom views and project pages"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Pro$q$, $q$$6/seat/month$q$, $q$Monthly or annual (25% off annually)$q$, NULL, $q$["Unlimited seats","1000 AI credits per seat","Workspace wiki and time tracking","Templates, dashboards and integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Business$q$, $q$$13/seat/month$q$, $q$Monthly or annual (13% off annually)$q$, NULL, $q$["Unlimited seats","2000 AI credits per seat","Project templates and intake forms","Customer profiles and advanced dashboards"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$Enterprise Grid$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom AI credit allocation","Private and managed deployments","SSO/LDAP and audit logs","Migration services"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Plane, at plane.so, is an open-source, AI-native project management platform positioned as an alternative to Jira, Linear, Asana and ClickUp. It was founded in late 2022 by brothers Vamsi Kurama and Vihar Kurama, operating out of Hyderabad, India and a US entity in Delaware/San Francisco.$q$, $q$Note for buyers: this is a different company from Plane at plane.com, a global payroll and HR platform founded independently in 2017; the two products share only a name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Plane organizes work into issues, Cycles for sprint tracking with burndown charts, and Modules for breaking large projects into components, alongside customizable board, list, spreadsheet and timeline views.$q$, $q$It includes a built-in Wiki linked to work items and Plane AI for AI-assisted workflows, and can be deployed as a managed Plane Cloud service or self-hosted via Docker or Kubernetes, including air-gapped enterprise setups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Plane follows a freemium, per-seat model: the Free tier supports up to 12 users, Pro is $6/seat/month, and Business is $13/seat/month, each with an increasing allocation of AI credits per seat.$q$, $q$Enterprise Grid is custom-priced for organizations that need private or managed deployments, SSO/LDAP, audit logs and migration support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68399520-7bce-4cbd-8fad-93972635411f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess-powered horizontal sharding$q$, $q$Scale MySQL-compatible databases across many nodes using the same technology that powers YouTube's database layer.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Managed PostgreSQL$q$, $q$Fully managed Postgres clusters with high-availability and bare-metal NVMe options.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Database branching$q$, $q$Create Git-style, isolated database branches for schema changes and testing before merging to production.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Online, non-blocking schema changes$q$, $q$Apply schema changes without downtime or table locks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Query Insights$q$, $q$Built-in monitoring for slow queries and query performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$High availability$q$, $q$Up to 99.999% SLA on multi-region deployments with automatic failover.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Enterprise-grade security$q$, $q$SOC 2 Type 2, HIPAA and PCI DSS Level 1 compliance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Built by the original creators of Vitess, with deep expertise in scaling relational databases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Git-style branching and non-blocking schema changes reduce migration risk$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Proven at massive scale, with Vitess powering Slack, GitHub, Block and Bloomberg$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Strong compliance posture, including SOC 2, HIPAA and PCI DSS, suits regulated industries$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Now offers both Vitess/MySQL and native Postgres products$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$No free tier since the Hobby plan was discontinued in April 2024, raising the barrier for side projects and small apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Pricing can scale quickly for high-availability, multi-region deployments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Shift toward enterprise focus may be less attractive to solo developers and small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess sharding model adds architectural complexity compared to a plain managed database$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Does PlanetScale have a free tier?$q$, $q$No, PlanetScale discontinued its free Hobby tier in April 2024; all current plans are paid, starting around $5/month for a small Postgres database.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Who founded PlanetScale?$q$, $q$PlanetScale was founded in 2018 by Jiten Vaidya and Sugu Sougoumarane, the original creators of Vitess.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$What is Vitess?$q$, $q$Vitess is an open-source database clustering system for horizontal scaling of MySQL, originally built at YouTube; PlanetScale is built and maintained by its creators.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Does PlanetScale support PostgreSQL?$q$, $q$Yes, alongside its original Vitess/MySQL product, PlanetScale offers managed PostgreSQL, including a high-performance PlanetScale Metal NVMe option.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$What is database branching?$q$, $q$A workflow that lets developers create isolated copies of a database schema, like Git branches, to test changes safely before deploying to production.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Is PlanetScale suitable for regulated industries?$q$, $q$Yes, it holds SOC 2 Type 2, HIPAA and PCI DSS Level 1 compliance certifications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$How much does PlanetScale cost?$q$, $q$Pricing starts around $5/month for a small non-HA Postgres instance and $39/month for entry-level Vitess clusters, scaling up based on compute, storage and high-availability needs.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$What are PlanetScale's main competitors?$q$, $q$AWS Aurora, Google Cloud SQL/AlloyDB, Neon, CockroachDB and Supabase.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Scaling MySQL at high traffic volume$q$, $q$Engineering teams migrate to PlanetScale's Vitess-based sharding to scale MySQL-compatible workloads beyond a single database instance.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Safe schema migrations via branching$q$, $q$Development teams use database branches to test and review schema changes before merging into production, similar to a Git workflow.$q$, $q$Application development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Regulated, compliance-sensitive workloads$q$, $q$Companies in healthcare, finance and other regulated industries run PlanetScale for its SOC 2, HIPAA and PCI DSS compliance.$q$, $q$Enterprises in regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Postgres Non-HA (single node)$q$, $q$From $5/month$q$, $q$Monthly$q$, NULL, $q$["Single-node development database","AWS and GCP regions","Prorated branch environments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Postgres HA (3-node)$q$, $q$From $15/month$q$, $q$Monthly$q$, NULL, $q$["Primary plus 2 replicas","Automatic failover","Scales up to 256 GiB and beyond"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$PlanetScale Metal$q$, $q$From $50/month$q$, $q$Monthly$q$, NULL, $q$["NVMe-backed storage","Unlimited IOPS","Cluster plus storage plus backups plus egress"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess Non-Metal$q$, $q$From $39/month$q$, $q$Monthly$q$, NULL, $q$["3-node cluster (1 primary, 2 replicas)","x86-64 architecture","17 configurable SKU tiers"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess Metal$q$, $q$From $609/month$q$, $q$Monthly$q$, NULL, $q$["Dedicated bare-metal Vitess cluster","Configurable storage up to approximately 15 TiB","Optional dedicated VTGates"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PlanetScale is a cloud database platform providing fully managed, horizontally scalable MySQL databases built on Vitess, plus a newer managed PostgreSQL product. It was founded in 2018 by Jiten Vaidya and Sugu Sougoumarane, the original creators of Vitess, and is headquartered in San Francisco.$q$, $q$The company has raised over $100 million from investors including Andreessen Horowitz, Insight Partners and Kleiner Perkins, and the underlying Vitess technology is used directly by large-scale platforms such as Slack, GitHub, Block and Bloomberg.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PlanetScale's core differentiator is Vitess-powered horizontal sharding combined with Git-style, non-blocking schema branching, letting developers create isolated database branches and test schema changes safely before merging without downtime.$q$, $q$The platform also offers Query Insights for performance monitoring, connection pooling, high-availability configurations with up to 99.999% SLA, and enterprise-grade compliance including SOC 2 Type 2, HIPAA and PCI DSS Level 1.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$In March 2024, PlanetScale discontinued its free Hobby tier as it shifted focus toward enterprise customers; pricing now starts around $5/month for a single-node Postgres development database and $39/month for entry-level Vitess clusters.$q$, $q$Costs scale with compute, storage and high-availability requirements, reaching into the tens of thousands of dollars per month for large, multi-region, bare-metal deployments.$q$]::text[], 2);
